48	/** Whether the descriptor represents, directly or not, a witness program. */
49	static bool IsSegwit(const Descriptor& desc) {
50	    if (const auto typ = desc.GetOutputType()) return *typ != OutputType::LEGACY;
51	    return false;
52	}
